mapper.select:
select id, title, option_type,is_default, price, status
from options

    option_type = #{optionType}

        AND title like concat('%',#{title},'%')


        AND status = #{status}


order by id

mapper.update:
update options
title = #{title}, option_type = #{optionType} , is_default = #{isDefault} , price = #{price}, status = #{status}, update_id = #{updateId}, update_time = #{updateTime}
where id = #{id}
